        }
    }

    // Step 2: Sorting Vowel Instances
    // Sort criteria: 
    // 1. Frequency (descending)
    // 2. First appearance index (ascending)
    uniqueVowels.sort((v1, v2) => {
        const count1 = counts.get(v1)!;
        const count2 = counts.get(v2)!;

        // Compare frequency (descending)
        if (count1 !== count2) {
            return count2 - count1;
        }

        // Frequencies are equal, compare first index (ascending)
        const index1 = firstIndex.get(v1)!;
        const index2 = firstIndex.get(v2)!;
        return index1 - index2;
    });

    // Build the target sequence of all vowels
    const targetVowelSequence: string[] = [];
    for (const vowel of uniqueVowels) {
        const count = counts.get(vowel)!;
        for (let i = 0; i < count; i++) {
            targetVowelSequence.push(vowel);
        }
    }

    // Step 3: Reconstruction
    const result = Array(s.length);
    let vowelPointer = 0;

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (VOWELS.has(char)) {
            // Replace vowel with the next vowel from the sorted sequence
            result[i] = targetVowelSequence[vowelPointer];
            vowelPointer++;
        } else {
            // Consonants remain in place
            result[i] = char;
        }
    }

    return result.join('');
}

